import{_ as e,H as t,f as d,i as a}from"./chunks/framework.BHvCMIhP.js";const m=JSON.parse('{"title":"Go 学习路线总览","description":"","frontmatter":{},"headers":[],"relativePath":"goLearning/01-Go学习路线总览.md","filePath":"goLearning/01-Go学习路线总览.md","lastUpdated":1778496697000}'),l={name:"goLearning/01-Go学习路线总览.md"};function i(r,o,c,n,h,s){return t(),d("div",null,[...o[0]||(o[0]=[a('<h1 id="go-学习路线总览" tabindex="-1">Go 学习路线总览 <a class="header-anchor" href="#go-学习路线总览" aria-label="Permalink to &quot;Go 学习路线总览&quot;">​</a></h1><p>这是一份为<strong>已经有其他语言（如 JS/TS、Java、C++）基础的开发者</strong>准备的 Go (Golang) 学习路线图。 从 &quot;Hello World&quot; 到 &quot;并发模型(Goroutine/Channel)&quot;，再到 &quot;微服务、K8s与云原生实践&quot; 的完整闭环。</p><blockquote><p>一句话先记住：Go 的设计哲学是<strong>大道至简</strong>。它用极简的语法（没有类、没有继承、没有泛型狂热）加上极强的并发模型，成为了<strong>云原生时代（Docker, Kubernetes）的绝对统治者</strong>。</p></blockquote><hr><h2 id="一、整套教程的结构" tabindex="-1">一、整套教程的结构 <a class="header-anchor" href="#一、整套教程的结构" aria-label="Permalink to &quot;一、整套教程的结构&quot;">​</a></h2><p>按 &quot;从基础到云原生实战&quot; 分五部分，<strong>前三部分讲语言与并发机制，后两部分讲工程与微服务</strong>：</p><table tabindex="0"><thead><tr><th>部分</th><th>主题</th><th>解决的核心问题</th></tr></thead><tbody><tr><td>一、基础与语法</td><td>变量、函数、结构体、接口</td><td>掌握极简主义的 Go 语言基础与面向接口编程</td></tr><tr><td>二、底层与进阶</td><td>内存、指针、反射、错误处理</td><td>理解 Go 的底层结构（Slice/Map）与工程规范</td></tr><tr><td>三、并发编程(核心)</td><td>Goroutine、Channel、Context</td><td><strong>Go 的灵魂所在</strong>，如何优雅地处理高并发</td></tr><tr><td>四、Web 与网络服务</td><td>HTTP、框架、数据库、gRPC</td><td>用 Go 干后端真实的活（Gin/GORM/微服务基础）</td></tr><tr><td>五、高级实战与调优</td><td>性能剖析(pprof)、GC、云原生结合</td><td>榨干性能，深入剖析运行时，对接 K8s/Docker 生态</td></tr></tbody></table><hr><h2 id="二、完整目录-规划约-30-篇" tabindex="-1">二、完整目录（规划约 30 篇） <a class="header-anchor" href="#二、完整目录-规划约-30-篇" aria-label="Permalink to &quot;二、完整目录（规划约 30 篇）&quot;">​</a></h2><h3 id="第一部分-基础语法与面向接口" tabindex="-1">第一部分：基础语法与面向接口 <a class="header-anchor" href="#第一部分-基础语法与面向接口" aria-label="Permalink to &quot;第一部分：基础语法与面向接口&quot;">​</a></h3><ul><li><code>02-环境搭建与Go Modules全家桶.md</code> —— <code>go mod</code>：极简而强大的包管理</li><li><code>03-基础语法速通.md</code> —— 变量、数据类型、控制流与 defer</li><li><code>04-数组、切片(Slice)与映射(Map).md</code> —— 日常开发最常用的数据结构</li><li><code>05-函数与多返回值.md</code> —— 一等公民与多返回值的最佳实践</li><li><code>06-结构体(Struct)与方法.md</code> —— 没有 Class，如何做面向对象编程？</li><li><code>07-接口(Interface)与鸭子类型.md</code> —— Go 语言多态的灵魂</li></ul><h3 id="第二部分-核心机制与工程规范" tabindex="-1">第二部分：核心机制与工程规范 <a class="header-anchor" href="#第二部分-核心机制与工程规范" aria-label="Permalink to &quot;第二部分：核心机制与工程规范&quot;">​</a></h3><ul><li><code>08-指针与内存布局基础.md</code> —— 为什么到处都是 <code>&amp;</code> 和 <code>*</code></li><li><code>09-错误处理与Panic-Recover机制.md</code> —— 为什么会有这么多 <code>if err != nil</code>？</li><li><code>10-底层大起底：Slice与Map是怎么实现的.md</code> —— 面试必问的底层扩容原理</li><li><code>11-类型断言与反射(Reflection).md</code> —— JSON 序列化和 ORM 是怎么做出来的</li><li><code>12-自动化测试与Mock.md</code> —— 表格驱动测试、基准测试(Benchmark)与 TDD</li><li><code>13-泛型(Generics).md</code> —— Go 1.18 之后的新世界</li></ul><h3 id="第三部分-并发编程-goroutine-与-channel" tabindex="-1">第三部分：并发编程（Goroutine 与 Channel） <a class="header-anchor" href="#第三部分-并发编程-goroutine-与-channel" aria-label="Permalink to &quot;第三部分：并发编程（Goroutine 与 Channel）&quot;">​</a></h3><ul><li><code>14-并发模型：Goroutine与GMP调度器.md</code> —— 为什么单机能跑百万个 Goroutine？</li><li><code>15-Channel：不要通过共享内存来通信.md</code> —— 无缓冲、有缓冲与 select 多路复用</li><li><code>16-sync包：Mutex, WaitGroup与Map.md</code> —— 传统的并发同步利器</li><li><code>17-Context：控制超时与上下文取消.md</code> —— 每个 Go 后端函数第一个参数为什么都是 ctx？</li><li><code>18-经典并发模式实战.md</code> —— Worker Pool、Fan-in/Fan-out 与 Pipeline</li><li><code>19-并发陷阱：竞态条件与死锁分析.md</code> —— 用 <code>go run -race</code> 找出并发 Bug</li></ul><h3 id="第四部分-web-实战与服务开发" tabindex="-1">第四部分：Web 实战与服务开发 <a class="header-anchor" href="#第四部分-web-实战与服务开发" aria-label="Permalink to &quot;第四部分：Web 实战与服务开发&quot;">​</a></h3><ul><li><code>20-标准库net-http与路由机制.md</code> —— 不用框架也能写高性能 Web 服务</li><li><code>21-Gin框架实战(一)：路由、中间件与鉴权.md</code> —— 最流行的 Go Web 框架</li><li><code>22-数据库交互实战：database-sql与GORM.md</code> —— 关系型数据库操作的最佳姿势</li><li><code>23-NoSQL交互：Redis与Elasticsearch.md</code> —— 高并发场景的缓存与检索</li><li><code>24-微服务通信：RPC与gRPC.md</code> —— Protobuf 与跨语言服务调用</li><li><code>25-Gin框架实战(二)：项目目录分层设计.md</code> —— Clean Architecture 在 Go 中的落地</li></ul><h3 id="第五部分-云原生与性能调优" tabindex="-1">第五部分：云原生与性能调优 <a class="header-anchor" href="#第五部分-云原生与性能调优" aria-label="Permalink to &quot;第五部分：云原生与性能调优&quot;">​</a></h3><ul><li><code>26-性能剖析利器：pprof与trace.md</code> —— 找出 CPU、内存与 Goroutine 泄漏的元凶</li><li><code>27-垃圾回收(GC)机制与内存逃逸分析.md</code> —— 三色标记法与如何减少堆分配</li><li><code>28-Go与Docker：编写极致的Dockerfile.md</code> —— Multi-stage build 与几兆的超小镜像</li><li><code>29-Go与Kubernetes：Operator开发基础.md</code> —— 用 Go 写云原生扩展</li><li><code>30-实战：手写一个高并发短链接服务.md</code> —— 整合全系列知识的最终章</li></ul><hr><h2 id="三、推荐的工具链" tabindex="-1">三、推荐的工具链 <a class="header-anchor" href="#三、推荐的工具链" aria-label="Permalink to &quot;三、推荐的工具链&quot;">​</a></h2><table tabindex="0"><thead><tr><th>用途</th><th>工具</th><th>备注</th></tr></thead><tbody><tr><td>IDE/编辑器</td><td>GoLand (JetBrains) / VSCode (Go插件) / Cursor</td><td><code>GoLand</code> 开箱即用体验最好</td></tr><tr><td>编译器套件</td><td>go build, go run, go test</td><td>Go 的工具链非常纯粹且内置完备</td></tr><tr><td>格式化与Lint</td><td>gofmt, golangci-lint</td><td><code>gofmt</code> 终结了缩进与大括号换行的圣战</td></tr><tr><td>版本管理</td><td>gvm / asdf / goenv</td><td>用于在同一台机器切换多个 Go 版本</td></tr></tbody></table><hr><h2 id="四、给新手的几个忠告" tabindex="-1">四、给新手的几个忠告 <a class="header-anchor" href="#四、给新手的几个忠告" aria-label="Permalink to &quot;四、给新手的几个忠告&quot;">​</a></h2><ol><li><strong>接受 <code>if err != nil</code>。</strong> 不要觉得麻烦，显式处理错误是 Go 的核心哲学，它让你的代码在生产环境极度稳定。</li><li><strong>少用反射(Reflection)和 <code>interface{}</code>。</strong> Go 是强类型静态语言，虽然反射能实现黑魔法，但在高频路径下会导致严重的性能问题。</li><li><strong>并发不是并行。</strong> 不要随手就开个 Goroutine 去跑任务，没有限制的 Goroutine 是服务 OOM（内存泄漏）的罪魁祸首。</li><li><strong>组合优于继承。</strong> 抛弃 Java/C++ 那套深层次的类继承体系，在 Go 里，通过把小接口结构体拼装在一起来复用代码。</li></ol><hr><p>下一篇：<code>02-环境搭建与Go Modules全家桶.md</code>，十分钟搞定开发环境。</p>',27)])])}const G=e(l,[["render",i]]);export{m as __pageData,G as default};
